    } catch (e) {
      return Left(ServerFailure(message: e.toString()));
    }
  }

  // ── Business Logic: compareOffers ──────────────────────────
  //
  // Compares 24 fields across two offers.
  // Returns (hasChanges, changedFields) tuple.

  static const _trackedPricingFields = ['list_price', 'purchase_price'];
  static const _trackedFinancialFields = [
    'loan_type',
    'down_payment_amount',
    'loan_amount',
    'deposit_amount',
    'deposit_type',
    'additional_earnest',
    'option_fee',
    'credit_request',
    'coverage_amount',
  ];
  static const _trackedConditionFields = [
    'property_condition',
    'pre_approval',
    'survey',
  ];
  static const _trackedTitleFields = ['company_name', 'choice'];
  static const _trackedContactFields = ['name', 'phone_number', 'email'];
  static const _trackedAddressFields = [
    'street_number',
    'street_name',
    'city',
    'state',
    'zip',
  ];

  /// Compare two offer JSON data objects.
  /// Returns `true` if any tracked field differs.
  bool compareOffers(Map<String, dynamic> newOffer,
      Map<String, dynamic> oldOffer) {
    // Pricing
    final newPricing = newOffer['pricing'] as Map<String, dynamic>? ?? {};
    final oldPricing = oldOffer['pricing'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedPricingFields) {
      if (_differs(newPricing[f], oldPricing[f])) return true;
    }

    // Financials
    final newFin = newOffer['financials'] as Map<String, dynamic>? ?? {};
    final oldFin = oldOffer['financials'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedFinancialFields) {
      if (_differs(newFin[f], oldFin[f])) return true;
    }

    // Closing date
    if (_differs(newOffer['closing_date'], oldOffer['closing_date'])) {
      return true;
    }

    // Conditions
    final newCond = newOffer['conditions'] as Map<String, dynamic>? ?? {};
    final oldCond = oldOffer['conditions'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedConditionFields) {
      if (_differs(newCond[f], oldCond[f])) return true;
    }

    // Title company
    final newTitle =
        newOffer['title_company'] as Map<String, dynamic>? ?? {};
    final oldTitle =
        oldOffer['title_company'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedTitleFields) {
      if (_differs(newTitle[f], oldTitle[f])) return true;
    }

    // Parties: buyer, second_buyer, agent
    for (final role in ['buyer', 'second_buyer', 'agent']) {
      final newParty =
          (newOffer['parties'] as Map<String, dynamic>? ?? {})[role]
              as Map<String, dynamic>? ??
              {};
      final oldParty =
          (oldOffer['parties'] as Map<String, dynamic>? ?? {})[role]
              as Map<String, dynamic>? ??
              {};
      for (final f in _trackedContactFields) {
        if (_differs(newParty[f], oldParty[f])) return true;
      }
    }

    // Property address
    final newAddr =
        (newOffer['property'] as Map<String, dynamic>? ?? {})['address']
            as Map<String, dynamic>? ??
            {};
    final oldAddr =
        (oldOffer['property'] as Map<String, dynamic>? ?? {})['address']
            as Map<String, dynamic>? ??
            {};
    for (final f in _trackedAddressFields) {
      if (_differs(newAddr[f], oldAddr[f])) return true;
    }

    return false;
  }

  /// Get a list of field names that differ between two offers.
  List<String> getChangedFields(Map<String, dynamic> newOffer,
      Map<String, dynamic> oldOffer) {
    final changed = <String>[];

    final newPricing = newOffer['pricing'] as Map<String, dynamic>? ?? {};
    final oldPricing = oldOffer['pricing'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedPricingFields) {
      if (_differs(newPricing[f], oldPricing[f])) changed.add('pricing.$f');
    }

    final newFin = newOffer['financials'] as Map<String, dynamic>? ?? {};
    final oldFin = oldOffer['financials'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedFinancialFields) {
      if (_differs(newFin[f], oldFin[f])) changed.add('financials.$f');
    }

    if (_differs(newOffer['closing_date'], oldOffer['closing_date'])) {
      changed.add('closing_date');
    }

    final newCond = newOffer['conditions'] as Map<String, dynamic>? ?? {};
    final oldCond = oldOffer['conditions'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedConditionFields) {
      if (_differs(newCond[f], oldCond[f])) changed.add('conditions.$f');
    }

    final newTitle =
        newOffer['title_company'] as Map<String, dynamic>? ?? {};
    final oldTitle =
        oldOffer['title_company'] as Map<String, dynamic>? ?? {};
    for (final f in _trackedTitleFields) {
      if (_differs(newTitle[f], oldTitle[f])) {
        changed.add('title_company.$f');
      }
    }

    for (final role in ['buyer', 'second_buyer', 'agent']) {
      final newParty =
          (newOffer['parties'] as Map<String, dynamic>? ?? {})[role]
              as Map<String, dynamic>? ??
              {};
      final oldParty =
          (oldOffer['parties'] as Map<String, dynamic>? ?? {})[role]
              as Map<String, dynamic>? ??
              {};
      for (final f in _trackedContactFields) {
        if (_differs(newParty[f], oldParty[f])) {
          changed.add('parties.$role.$f');
        }
      }
    }

    final newAddr =
        (newOffer['property'] as Map<String, dynamic>? ?? {})['address']
            as Map<String, dynamic>? ??
            {};
    final oldAddr =
        (oldOffer['property'] as Map<String, dynamic>? ?? {})['address']
            as Map<String, dynamic>? ??
            {};
    for (final f in _trackedAddressFields) {
      if (_differs(newAddr[f], oldAddr[f])) changed.add('address.$f');
    }

    return changed;
  }

  bool _differs(dynamic a, dynamic b) {
    if (a == null && b == null) return false;
    return a?.toString() != b?.toString();
  }
}

