    }
  }

  /// Create invitations AND send email + SMS to each invitee.
  Future<Either<Failure, void>> createBuyerInvitationsWithMessaging({
    required String inviterUid,
    required String inviterName,
    required String inviterFullName,
    required String signUpUrl,
    required String shortLink,
    required String logoUrl,
    String? inviterMLS,
    String? inviterContact,
    String? brokerageName,
    required List<Map<String, dynamic>> invitees,
    required String requesterId,
  }) async {
    try {
      // Send email + SMS to each invitee in parallel
      final futures = <Future>[];
      for (final invitee in invitees) {
        final firstName = (invitee['name'] as String?)?.split(' ').first ?? '';
        final email = invitee['email'] as String? ?? '';
        final phone = invitee['phone'] as String? ?? '';

        // Generate email HTML
        final emailHtml = generateInvitationEmailHtml(
          inviterName: inviterFullName,
          signUpUrl: signUpUrl,
          invitationType: 'buyer',
          logoUrl: logoUrl,
          inviterFullName: inviterFullName,
          inviterMLS: inviterMLS,
          inviterContact: inviterContact,
          brokerageName: brokerageName,
          inviteeFirstName: firstName,
        );

        if (email.isNotEmpty) {
          futures.add(_emailSms
              .sendEmail(
                to: email,
                subject:
                    'Use My Application to Make Offers on Properties with Just a Click \u2013 You\'re Invited!',
                body: emailHtml,
                cc: email,
                requesterId: requesterId,
              )
              .timeout(const Duration(seconds: 25)));
        }

        if (phone.isNotEmpty) {
          final smsText = generateInvitationSmsText(
            firstName: firstName,
            shortLink: shortLink,
            agentName: inviterFullName,
            invitationType: 'buyer',
          );
          futures.add(_emailSms
              .sendSms(
                recipient: phone,
                content: smsText,
                sender: inviterFullName,
                requesterId: requesterId,
              )
              .timeout(const Duration(seconds: 25)));
        }
      }

      await Future.wait(futures);

      // Then create Firestore records
      await _firestore.createInvitations(
        inviterUid: inviterUid,
        inviterName: inviterName,
        invitees: invitees,
      );

      return const Right(null);
    } catch (e) {
      return Left(ServerFailure(message: e.toString()));
    }
  }

