  // ── Business Logic: Merge contacts with invitations ────────

  List<Map<String, dynamic>> mergeContactsWithInvitations({
    required List<Map<String, dynamic>> apiContacts,
    required List<Map<String, dynamic>> firebaseInvitations,
    required String selectedTab,
  }) {
    if (selectedTab == 'CRM') {
      // Show all API contacts, enrich with invitation status
      final invitationByEmail = <String, Map<String, dynamic>>{};
      for (final inv in firebaseInvitations) {
        final email = (inv['inviteeEmail'] as String?)?.toLowerCase() ?? '';
        if (email.isNotEmpty) invitationByEmail[email] = inv;
      }
      return apiContacts.map((contact) {
        final email =
            (contact['email'] as String?)?.toLowerCase() ?? '';
        final inv = invitationByEmail[email];
        return {
          ...contact,
          if (inv != null) 'invitationStatus': inv['status'],
          if (inv != null) 'invitationId': inv['id'],
        };
      }).toList();
    } else {
      // My Contacts: show Firebase invitations not in API contacts
      final apiEmails = apiContacts
          .map((c) => (c['email'] as String?)?.toLowerCase() ?? '')
          .toSet();
      return firebaseInvitations
          .where((inv) {
            final email =
