  }) {
    // Build lookup maps
    final nameMap = <String, String>{};
    final photoMap = <String, String>{};
    for (final c in clients) {
      final id = c['clientID']?.toString() ?? '';
      nameMap[id] = c['fullName']?.toString() ?? '';
      photoMap[id] = c['photoUrl']?.toString() ?? '';
    }

    final enriched = <Map<String, dynamic>>[];
    for (final activity in activities) {
      final userId = activity['user_id']?.toString() ?? '';
      enriched.add({
        ...activity,
        'memberName': nameMap[userId] ?? 'Unknown',
        'memberPhoto': photoMap[userId] ?? '',
        'activityType': activity['search'] != null ? 'search' : 'other',
      });
    }

    // Sort by timestamp descending
    enriched.sort((a, b) {
      final aTime = a['created_at']?.toString() ?? '';
      final bTime = b['created_at']?.toString() ?? '';
      return bTime.compareTo(aTime);
    });

